 1→import { useEffect, useRef } from 'react';
 2→
 3→export default function Modal({ title, onClose, children }) {
 4→  const overlayRef = useRef(null);
 5→
 6→  useEffect(() => {
 7→    const handleKey = (e) => {
 8→      if (e.key === 'Escape') onClose();
 9→    };
10→    window.addEventListener('keydown', handleKey);
11→    return () => window.removeEventListener('keydown', handleKey);
12→  }, [onClose]);
13→
14→  const handleOverlayClick = (e) => {
15→    if (e.target === overlayRef.current) onClose();
16→  };
17→
18→  return (
19→    <div
20→      ref={overlayRef}
21→      onClick={handleOverlayClick}
22→      style={{
23→        position: 'fixed',
24→        inset: 0,
25→        background: 'rgba(10, 12, 15, 0.45)',
26→        backdropFilter: 'blur(4px)',
27→        display: 'flex',
28→        alignItems: 'center',
29→        justifyContent: 'center',
30→        zIndex: 1000,
31→        animation: 'modalOverlayIn 0.2s ease',
32→      }}
33→    >
34→      <div style={{
35→        background: '#FAFAF8',
36→        borderRadius: 'var(--radius-lg)',
37→        padding: 'var(--space-xl)',
38→        minWidth: '360px',
39→        maxWidth: '480px',
40→        boxShadow: 'var(--shadow-overlay)',
41→        border: '1px solid var(--color-border)',
42→        animation: 'modalDialogIn 0.25s var(--ease-out)',
43→      }}>
44→        <h3 style={{
45→          margin: '0 0 16px',
46→          fontSize: '16px',
47→          fontWeight: 600,
48→          letterSpacing: '-0.01em',
49→        }}>
50→          {title}
51→        </h3>
52→        {children}
53→      </div>
54→    </div>
55→  );
56→}
